/**
 * Try to identify which loyalty program a barcode belongs to.
 * Matches by known BIN/prefix. Returns null if unknown.
 */
export function detectProgram(barcode: string): LoyaltyProgram | null {
  const digits = barcode.replace(/\D/g, "");
  // Prefer longer (more specific) prefix matches
  let best: LoyaltyProgram | null = null;
  let bestLen = 0;
  for (const prog of LOYALTY_PROGRAMS) {
    for (const prefix of prog.prefixes) {
      if (digits.startsWith(prefix) && prefix.length > bestLen) {
        best = prog;
        bestLen = prefix.length;
      }
    }
  }
  return best;
}
